def rate_limit(f):
    """Rate limiting decorator."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        client_ip = request.remote_addr
        current_time = time.time()

        if client_ip in rate_limit_store:
            window_data = rate_limit_store[client_ip]
            if current_time - window_data['window_start'] > RATE_LIMIT_WINDOW:
                rate_limit_store[client_ip] = {'count': 1, 'window_start': current_time}
            else:
                window_data['count'] += 1
                if window_data['count'] > RATE_LIMIT_MAX_REQUESTS:
                    return jsonify({"error": "rate_limit_exceeded",
                                    "error_description": "Too many requests"}), 429
        else:
            rate_limit_store[client_ip] = {'count': 1, 'window_start': current_time}

        return f(*args, **kwargs)
    return decorated_function


