def login():
    """Handle user authentication and generate authorization code."""
    content_type = request.content_type or ''

    if 'application/json' in content_type:
        data = request.get_json(silent=True) or {}
    else:
        data = request.form

    username = data.get('username', '')
    password = data.get('password', '')

    if not username or not password:
        return jsonify({"error": "invalid_request",
                        "error_description": "Username and password are required"}), 400

    # Authenticate user
    if username not in users:
        # Use constant time comparison even for missing users to prevent enumeration
        _verify_secret(password, _hash_secret("dummy"))
        return jsonify({"error": "access_denied",
                        "error_description": "Invalid credentials"}), 401

    user = users[username]
    if not _verify_secret(password, user['password_hash']):
        return jsonify({"error": "access_denied",
                        "error_description": "Invalid credentials"}), 401

    # Get authorization request from session
    auth_request = session.get('auth_request')
    if not auth_request:
        return jsonify({"error": "invalid_request",
                        "error_description": "No pending authorization request. Start at /authorize"}), 400

    # Generate authorization code
    code = _generate_secure_token(32)
    code_hash = _hash_token(code)

    # Store code with metadata (using hash as key for secure storage)
